package petriage

import (
	"encoding/base64"
	"math"
	"strings"
	"testing"
)

// mingwPE is a real gcc/mingw-built 32-bit Windows console PE (the Go
// toolchain's own debug/pe corpus: gcc-386-mingw-no-symbols-exec). Ground
// truth from debug/pe: Machine i386, 8 sections, subsystem 3 (console),
// AddressOfEntryPoint 0x1280, DllCharacteristics 0 (no ASLR/DEP/CFG), imports
// from KERNEL32.dll + msvcrt.dll including VirtualProtect and GetProcAddress.
const mingwPE = ""

func decode(t *testing.T, b64 string) *Result {
	t.Helper()
	raw := mustB64(t, b64)
	r, err := Decode(raw)
	if err != nil {
		t.Fatalf("Decode: %v", err)
	}
	return r
}

func TestDecode_MingwPE(t *testing.T) {
	r := decode(t, mingwPE)
	if r.Bits != 32 || r.Machine != "x86" {
		t.Errorf("bits=%d machine=%q, want 32 / x86", r.Bits, r.Machine)
	}
	if !strings.HasPrefix(r.Type, "EXE") {
		t.Errorf("type = %q, want EXE", r.Type)
	}
	if r.Subsystem != "Windows console" {
		t.Errorf("subsystem = %q, want Windows console", r.Subsystem)
	}
	if r.EntryPoint != "0x1280" {
		t.Errorf("entry = %q, want 0x1280", r.EntryPoint)
	}
	if len(r.Sections) != 8 {
		t.Errorf("sections = %d, want 8", len(r.Sections))
	}
	if !contains(r.ImportedDLLs, "KERNEL32.dll") || !contains(r.ImportedDLLs, "msvcrt.dll") {
		t.Errorf("imported DLLs = %v", r.ImportedDLLs)
	}
	if !contains(r.ImportedSymbols, "VirtualProtect") || !contains(r.ImportedSymbols, "GetProcAddress") {
		t.Errorf("imported symbols missing expected entries: %v", r.ImportedSymbols)
	}
	if !contains(r.SuspiciousSymbols, "VirtualProtect") || !contains(r.SuspiciousSymbols, "GetProcAddress") {
		t.Errorf("suspicious symbols = %v, want VirtualProtect + GetProcAddress", r.SuspiciousSymbols)
	}
	// DllCharacteristics is 0 → every mitigation is absent.
	for _, m := range []string{"ASLR", "DEP", "CFG"} {
		if !contains(r.MissingMitigations, m) {
			t.Errorf("missing mitigation %q not reported: %v", m, r.MissingMitigations)
		}
	}
	if len(r.Mitigations) != 0 {
		t.Errorf("mitigations = %v, want none", r.Mitigations)
	}
	if !r.Suspicious || !strings.Contains(r.Note, "SUSPICIOUS") {
		t.Errorf("expected suspicious verdict: %+v", r.SuspiciousReasons)
	}
}

func TestDecode_Errors(t *testing.T) {
	for name, in := range map[string][]byte{
		"empty":   {},
		"not pe":  []byte("ELF this is not a PE"),
		"mz only": []byte("MZ\x00\x00 truncated, no PE header"),
	} {
		if _, err := Decode(in); err == nil {
			t.Errorf("%s: expected error", name)
		}
	}
}

func TestPackerName(t *testing.T) {
	cases := map[string]string{
		"UPX0":             "UPX",
		"UPX1\x00\x00\x00": "UPX",
		".vmp0":            "VMProtect",
		"MPRESS1":          "MPRESS",
		".text":            "",
		".data":            "",
	}
	for in, want := range cases {
		if got := packerName(in); got != want {
			t.Errorf("packerName(%q) = %q, want %q", in, got, want)
		}
	}
}

func TestSuspiciousAPI_CaseAndVariants(t *testing.T) {
	// Lookup lower-cases the symbol, so case and A/W variants all match.
	for _, sym := range []string{"VirtualAllocEx", "writeprocessmemory", "CreateRemoteThread", "URLDownloadToFileW", "ShellExecuteA"} {
		if !suspiciousAPIs[strings.ToLower(sym)] {
			t.Errorf("expected %q to be a suspicious API", sym)
		}
	}
	for _, sym := range []string{"printf", "GetTickCount64", "memcpy"} {
		if suspiciousAPIs[strings.ToLower(sym)] {
			t.Errorf("did not expect %q to be flagged", sym)
		}
	}
}

func TestEntropyExtremes(t *testing.T) {
	// All-zero data → entropy 0; uniformly distributed bytes → ~8.
	zero := make([]byte, 4096)
	if h := shannon(zero); h != 0 {
		t.Errorf("zero entropy = %f, want 0", h)
	}
	uni := make([]byte, 256*16)
	for i := range uni {
		uni[i] = byte(i % 256)
	}
	if h := shannon(uni); h < 7.99 {
		t.Errorf("uniform entropy = %f, want ~8", h)
	}
}

func FuzzDecode(f *testing.F) {
	f.Add(mustB64(f, mingwPE))
	f.Add([]byte("MZ\x00\x00"))
	f.Add([]byte{})
	f.Fuzz(func(_ *testing.T, data []byte) {
		// Must never panic, regardless of input.
		_, _ = Decode(data)
	})
}

// --- test helpers ---------------------------------------------------------

// shannon computes Shannon entropy over a byte slice (independent re-derivation
// of the production math).
func shannon(data []byte) float64 {
	if len(data) == 0 {
		return 0
	}
	var counts [256]int
	for _, b := range data {
		counts[b]++
	}
	n := float64(len(data))
	var h float64
	for _, c := range counts {
		if c == 0 {
			continue
		}
		p := float64(c) / n
		h -= p * math.Log2(p)
	}
	return h
}

func contains(xs []string, s string) bool {
	for _, x := range xs {
		if x == s {
			return true
		}
	}
	return false
}

func mustB64(tb testing.TB, s string) []byte {
	tb.Helper()
	raw, err := base64.StdEncoding.DecodeString(s)
	if err != nil {
		tb.Fatalf("base64: %v", err)
	}
	return raw
}
